input.command:
SESSION=/Users/ns/.claude-st/projects/-private-tmp/aad255c7-d156-4514-92bc-81b8f2162707.jsonl
echo "---size---"; wc -c "$SESSION"
echo "---skill-invocations---"
python3 -c '
import json, sys
seen = []
with open("'"$SESSION"'") as f:
    for line in f:
        try:
            obj = json.loads(line)
        except Exception:
            continue
        msg = obj.get("message") or {}
        for c in (msg.get("content") or []) if isinstance(msg.get("content"), list) else []:
            if isinstance(c, dict) and c.get("type") == "tool_use" and c.get("name") == "Skill":
                inp = c.get("input") or {}
                seen.append(inp.get("skill"))
print(seen)
'

